AAA;AAEA,IAAM,aAAA,GAA4C;AAAA,EAChD,MAAA,EAAQ,aAAA;AAAA,EACR,QAAA,EAAU,eAAA;AAAA,EACV,IAAA,EAAM,WAAA;AAAA,EACN,KAAA,EAAO;AACT,CAAA;AAEA,IAAM,WAAA,GAAwC;AAAA,EAC5C,OAAA,EAAS,yBAAA;AAAA,EACT,SAAA,EAAW,6BAAA;AAAA,EACX,KAAA,EAAO,+BAAA;AAAA,EACP,QAAA,EAAU,4BAAA;AAAA,EACV,KAAA,EAAO,qBAAA;AAAA,EACP,MAAA,EAAQ;AACV,CAAA;AAEA,IAAM,eAAA,GAAgD;AAAA,EACpD,KAAA,EAAO,gBAAA;AAAA,EACP,MAAA,EAAQ,iBAAA;AAAA,EACR,IAAA,EAAM,eAAA;AAAA,EACN,MAAA,EAAQ;AACV,CAAA;AAMO,IAAM,IAAA,GAAO,UAAA;AAAA,EAClB,CACE;AAAA,IACE,IAAA,GAAO,QAAA;AAAA,IACP,MAAA,GAAS,QAAA;AAAA,IACT,IAAA,GAAO,SAAA;AAAA,IACP,QAAA;AAAA,IACA,SAAA,GAAY,KAAA;AAAA,IACZ,MAAA,GAAS,KAAA;AAAA,IACT,QAAA,GAAW,KAAA;AAAA,IACX,SAAA;AAAA,IACA,QAAA;AAAA,IACA,GAAG;AAAA,KAEL,GAAA,KACG;AACH,IAAA,uBACEC,GAAAA;AAAA,MAAC,MAAA;AAAA,MAAA;AAAA,QACC,GAAA;AAAA,QACA,SAAA,EAAWH,GAAAA;AAAA,UACT,kCAAA;AAAA;AAAA,UACA,YAAY,IAAI,CAAA;AAAA,UAChB,YAAY,IAAI,CAAA;AAAA,UAChB,cAAc,MAAM,CAAA;AAAA,UACpB,QAAA,GAAW,eAAA,CAAgB,QAAQ,CAAA,GAAI,SAAA,IAAa,eAAA;AAAA,UACpD,SAAA,IAAa,WAAA;AAAA,UACb,MAAA,IAAU,QAAA;AAAA,UACV,QAAA,IAAY,UAAA;AAAA,UACZ;AAAA,SACF;AAAA,QACC,GAAG,IAAA;AAAA,QAEH;AAAA;AAAA,KACH;AAAA,EAEJ;AACF;AAEA,IAAA,CAAK,WAAA,GAAc,MAAA;AC1FZ,IAAM,MAAA,GAASI,UAAAA;AAAA,EACpB,CAAC,EAAE,QAAA,EAAU,OAAA,GAAU,WAAW,IAAA,GAAO,IAAA,EAAM,SAAA,GAAY,EAAA,EAAI,EAAA,GAAK,QAAA,EAAU,GAAG,KAAA,IAAS,GAAA,KAAQ;AAEhG,IAAA,MAAM,IAAA,GAAO,8HAAA;AAEb,IAAA,MAAMC,YAAAA,GAA0C;AAAA,MAC9C,EAAA,EAAI,kBAAA;AAAA,MACJ,EAAA,EAAI,qBAAA;AAAA,MACJ,EAAA,EAAI;AAAA,KACN;AAEA,IAAA,MAAM,aAAA,GAA+C;AAAA,MACnD,OAAA,EAAS;AAAA,QACP,2BAAA;AAAA,QACA,uBAAA;AAAA,QACA;AAAA,OACF,CAAE,KAAK,GAAG,CAAA;AAAA,MAEV,SAAA,EAAW;AAAA,QACT,iDAAA;AAAA,QACA;AAAA,OACF,CAAE,KAAK,GAAG;AAAA,KACZ;AAEA,IAAA,MAAM,OAAA,GAAUH,MAAK,IAAA,EAAMG,YAAAA,CAAY,IAAI,CAAA,EAAG,aAAA,CAAc,OAAO,CAAA,EAAG,SAAS,CAAA;AAC/E,IAAA,MAAM,SAAA,GAAY,EAAA;AAElB,IAAA,uBACEF,IAAC,SAAA,EAAA,EAAU,SAAA,EAAW,SAAS,GAAA,EAAW,GAAI,OAC3C,QAAA,EACH,CAAA;AAAA,EAEJ;AACF;AAEA,MAAA,CAAO,WAAA,GAAc,QAAA","file":"index.js","sourcesContent":["import React from \"react\";\nimport { FiSend } from \"react-icons/fi\";\nimport { clsx, type ClassValue } from \"clsx\";\nimport { twMerge } from \"tailwind-merge\";\n\nfunction cn(...inputs: ClassValue[]) {\n  return twMerge(clsx(inputs));\n}\n\ntype Variant = \"mark\" | \"wordmark\" | \"lockup\";\ntype Size = \"xs\" | \"sm\" | \"md\" | \"lg\";\n\n// 📐 Aligned with your UI typography scale for perfect vertical rhythm\nconst sizeMap: Record<Size, { icon: string; text: string; gap: string }> = {\n  xs: { icon: \"text-base\", text: \"text-lg\", gap: \"gap-1\" },\n  sm: { icon: \"text-xl\", text: \"text-xl\", gap: \"gap-1.5\" },\n  md: { icon: \"text-2xl\", text: \"text-2xl\", gap: \"gap-2\" },\n  lg: { icon: \"text-3xl\", text: \"text-4xl\", gap: \"gap-2.5\" },\n};\n\nexport type LogoProps = {\n  variant?: Variant;\n  size?: Size;\n  mono?: boolean;\n  className?: string;\n  iconClassName?: string;\n  wordmarkClassName?: string;\n  \"aria-label\"?: string;\n};\n\nexport const Logo: React.FC<LogoProps> = ({\n  variant = \"lockup\",\n  size = \"md\",\n  mono = false,\n  className,\n  iconClassName,\n  wordmarkClassName,\n  \"aria-label\": ariaLabel = \"Unio\",\n  ...rest\n}) => {\n  const sizes = sizeMap[size];\n\n  // Logic for color normalization\n  const iconColor = mono ? \"text-foreground\" : \"text-accent\";\n  const wordmarkColor = mono ? \"text-foreground\" : \"text-text-primary\";\n\n  const Mark = (\n    <FiSend\n      className={cn(\n        sizes.icon,\n        \"flex-shrink-0 transition-colors duration-200\",\n        iconColor,\n        iconClassName\n      )}\n      aria-hidden=\"true\"\n    />\n  );\n\n  const Wordmark = (\n    <span\n      className={cn(\n        \"brand-font tracking-tight select-none antialiased\",\n        sizes.text,\n        wordmarkColor,\n        wordmarkClassName\n      )}\n    >\n      unio\n    </span>\n  );\n\n  return (\n    <span\n      role=\"img\"\n      aria-label={ariaLabel}\n      className={cn(\n        \"inline-flex items-center align-middle flex-shrink-0\",\n        sizes.gap,\n        className\n      )}\n      {...rest}\n    >\n      {variant !== \"wordmark\" && Mark}\n      {variant !== \"mark\" && Wordmark}\n    </span>\n  );\n};\n\nexport default Logo;\n","import React, { forwardRef, ComponentPropsWithRef } from \"react\";\nimport { clsx, type ClassValue } from \"clsx\";\nimport { twMerge } from \"tailwind-merge\";\n\nfunction cn(...inputs: ClassValue[]) {\n  return twMerge(clsx(inputs));\n}\n\n// --- Types ---\ntype TextSize = \"tiny\" | \"small\" | \"medium\" | \"large\" | \"xl\" | \"2xl\" | \"3xl\" | \"4xl\" | \"5xl\" | \"6xl\";\ntype TextWeight = \"normal\" | \"semibold\" | \"bold\" | \"black\";\ntype TextTone = \"default\" | \"secondary\" | \"muted\" | \"tertiary\" | \"brand\" | \"danger\";\ntype TextTracking = \"tight\" | \"normal\" | \"wide\" | \"widest\";\n\n/**\n * 🎯 Pure Text Props\n * We extend React.ComponentPropsWithRef<\"span\"> so it behaves \n * exactly like a span, but with our design tokens.\n */\nexport interface TextProps extends ComponentPropsWithRef<\"span\"> {\n  size?: TextSize;\n  weight?: TextWeight;\n  tone?: TextTone;\n  tracking?: TextTracking;\n  uppercase?: boolean;\n  italic?: boolean;\n  truncate?: boolean;\n}\n\nconst sizeClasses: Record<TextSize, string> = {\n  tiny: \"text-xs leading-4\",\n  small: \"text-sm leading-5\",\n  medium: \"text-base leading-6\",\n  large: \"text-lg leading-7\",\n  xl: \"text-xl leading-7\",\n  \"2xl\": \"text-2xl leading-8\",\n  \"3xl\": \"text-3xl leading-9\",\n  \"4xl\": \"text-4xl leading-10\",\n  \"5xl\": \"text-5xl leading-[3rem]\",\n  \"6xl\": \"text-6xl leading-[3.5rem]\",\n};\n\nconst weightClasses: Record<TextWeight, string> = {\n  normal: \"font-normal\",\n  semibold: \"font-semibold\",\n  bold: \"font-bold\",\n  black: \"font-black\",\n};\n\nconst toneClasses: Record<TextTone, string> = {\n  default: \"text-foreground font-ui\",\n  secondary: \"text-text-secondary font-ui\",\n  muted: \"text-foreground-muted font-ui\",\n  tertiary: \"text-text-tertiary font-ui\",\n  brand: \"text-accent font-ui\",\n  danger: \"text-danger font-ui\",\n};\n\nconst trackingClasses: Record<TextTracking, string> = {\n  tight: \"tracking-tight\",\n  normal: \"tracking-normal\",\n  wide: \"tracking-wide\",\n  widest: \"tracking-widest\",\n};\n\n/**\n * 🎨 Pure Unio Text\n * A strict span-based primitive. No 'as' prop, no 'any'.\n */\nexport const Text = forwardRef<HTMLSpanElement, TextProps>(\n  (\n    {\n      size = \"medium\",\n      weight = \"normal\",\n      tone = \"default\",\n      tracking,\n      uppercase = false,\n      italic = false,\n      truncate = false,\n      className,\n      children,\n      ...rest\n    },\n    ref\n  ) => {\n    return (\n      <span\n        ref={ref}\n        className={cn(\n          \"min-w-0 antialiased inline-block\", // inline-block helps with layout stability\n          toneClasses[tone],\n          sizeClasses[size],\n          weightClasses[weight],\n          tracking ? trackingClasses[tracking] : uppercase && \"tracking-wide\",\n          uppercase && \"uppercase\",\n          italic && \"italic\",\n          truncate && \"truncate\",\n          className\n        )}\n        {...rest}\n      >\n        {children}\n      </span>\n    );\n  }\n);\n\nText.displayName = \"Text\";\n\nexport default Text;","// packages/ui/src/components/Button.tsx\nimport React, { forwardRef, ElementType } from \"react\";\nimport clsx from \"clsx\";\n\ntype ButtonSize = \"sm\" | \"md\" | \"lg\";\ntype ButtonVariant = \"primary\" | \"secondary\";\n\nexport type PolymorphicButtonProps = {\n  as?: React.ElementType;\n  children: React.ReactNode;\n  variant?: ButtonVariant;\n  size?: ButtonSize;\n  className?: string;\n  to?: string; // For React Router Link\n  href?: string; // For Anchor\n} & React.HTMLAttributes<HTMLElement>;\n\nexport const Button = forwardRef<HTMLElement, PolymorphicButtonProps>(\n  ({ children, variant = \"primary\", size = \"md\", className = \"\", as = \"button\", ...props }, ref) => {\n    \n    const base = \"inline-flex items-center justify-center rounded-md font-semibold transition-all duration-200 select-none active:scale-[0.98]\";\n\n    const sizeClasses: Record<ButtonSize, string> = {\n      sm: \"h-9 px-4 text-sm\",\n      md: \"h-11 px-5 text-base\",\n      lg: \"h-12 px-6 text-lg\",\n    };\n\n    const variantStyles: Record<ButtonVariant, string> = {\n      primary: [\n        \"bg-accent text-background\", \n        \"hover:bg-accent-hover\", \n        \"shadow-sm hover:shadow-md\"\n      ].join(\" \"),\n\n      secondary: [\n        \"border border-accent text-accent bg-transparent\",\n        \"hover:bg-accent/10 hover:border-accent-hover hover:text-accent-hover\"\n      ].join(\" \"),\n    };\n\n    const classes = clsx(base, sizeClasses[size], variantStyles[variant], className);\n    const Component = as as ElementType;\n\n    return (\n      <Component className={classes} ref={ref} {...(props as any)}>\n        {children}\n      </Component>\n    );\n  }\n);\n\nButton.displayName = \"Button\";"]}
