nd\" : \"text-accent\";\n  const wordmarkColor = mono ? \"text-foreground\" : \"text-text-primary\";\n\n  const Mark = (\n    <FiSend\n      className={cn(\n        sizes.icon,\n        \"flex-shrink-0 transition-colors duration-200\",\n        iconColor,\n        iconClassName\n      )}\n      aria-hidden=\"true\"\n    />\n  );\n\n  const Wordmark = (\n    <span\n      className={cn(\n        \"brand-font tracking-tight select-none antialiased\",\n        sizes.text,\n        wordmarkColor,\n        wordmarkClassName\n      )}\n    >\n      unio\n    </span>\n  );\n\n  return (\n    <span\n      role=\"img\"\n      aria-label={ariaLabel}\n      className={cn(\n        \"inline-flex items-center align-middle flex-shrink-0\",\n        sizes.gap,\n        className\n      )}\n      {...rest}\n    >\n      {variant !== \"wordmark\" && Mark}\n      {variant !== \"mark\" && Wordmark}\n    </span>\n  );\n};\n\nexport default Logo;\n","import React, { forwardRef, ComponentPropsWithRef } from \"react\";\nimport { clsx, type ClassValue } from \"clsx\";\nimport { twMerge } from \"tailwind-merge\";\n\nfunction cn(...inputs: ClassValue[]) {\n  return twMerge(clsx(inputs));\n}\n\n// --- Types ---\ntype TextSize = \"tiny\" | \"small\" | \"medium\" | \"large\" | \"xl\" | \"2xl\" | \"3xl\" | \"4xl\" | \"5xl\" | \"6xl\";\ntype TextWeight = \"normal\" | \"semibold\" | \"bold\" | \"black\";\ntype TextTone = \"default\" | \"secondary\" | \"muted\" | \"tertiary\" | \"brand\" | \"danger\";\ntype TextTracking = \"tight\" | \"normal\" | \"wide\" | \"widest\";\n\n/**\n * 🎯 Pure Text Props\n * We extend React.ComponentPropsWithRef<\"span\"> so it behaves \n * exactly like a span, but with our design tokens.\n */\nexport interface TextProps extends ComponentPropsWithRef<\"span\"> {\n  size?: TextSize;\n  weight?: TextWeight;\n  tone?: TextTone;\n  tracking?: TextTracking;\n  uppercase?: boolean;\n  italic?: boolean;\n  truncate?: boolean;\n}\n\nconst sizeClasses: Record<TextSize, string> = {\n  tiny: \"text-xs leading-4\",\n  small: \"text-sm leading-5\",\n  medium: \"text-base leading-6\",\n  large: \"text-lg leading-7\",\n  xl: \"text-xl leading-7\",\n  \"2xl\": \"text-2xl leading-8\",\n  \"3xl\": \"text-3xl leading-9\",\n  \"4xl\": \"text-4xl leading-10\",\n  \"5xl\": \"text-5xl leading-[3rem]\",\n  \"6xl\": \"text-6xl leading-[3.5rem]\",\n};\n\nconst weightClasses: Record<TextWeight, string> = {\n  normal: \"font-normal\",\n  semibold: \"font-semibold\",\n  bold: \"font-bold\",\n  black: \"font-black\",\n};\n\nconst toneClasses: Record<TextTone, string> = {\n  default: \"text-foreground font-ui\",\n  secondary: \"text-text-secondary font-ui\",\n  muted: \"text-foreground-muted font-ui\",\n  tertiary: \"text-text-tertiary font-ui\",\n  brand: \"text-accent font-ui\",\n  danger: \"text-danger font-ui\",\n};\n\nconst trackingClasses: Record<TextTracking, string> = {\n  tight: \"tracking-tight\",\n  normal: \"tracking-normal\",\n  wide: \"tracking-wide\",\n  widest: \"tracking-widest\",\n};\n\n/**\n * 🎨 Pure Unio Text\n * A strict span-based primitive. No 'as' prop, no 'any'.\n */\nexport const Text = forwardRef<HTMLSpanElement, TextProps>(\n  (\n    {\n      size = \"medium\",\n      weight = \"normal\",\n      tone = \"default\",\n      tracking,\n      uppercase = false,\n      italic = false,\n      truncate = false,\n      className,\n      children,\n      ...rest\n    },\n    ref\n  ) => {\n    return (\n      <span\n        ref={ref}\n        className={cn(\n          \"min-w-0 antialiased inline-block\", // inline-block helps with layout stability\n          toneClasses[tone],\n          sizeClasses[size],\n          weightClasses[weight],\n          tracking ? trackingClasses[tracking] : uppercase && \"tracking-wide\",\n          uppercase && \"uppercase\",\n          italic && \"italic\",\n          truncate && \"truncate\",\n          className\n        )}\n        {...rest}\n      >\n        {children}\n      </span>\n    );\n  }\n);\n\nText.displayName = \"Text\";\n\nexport default Text;","// -----------------------------------------------------------------------------\n// 📁 packages/ui/src/components/button/Button.tsx\n// -----------------------------------------------------------------------------\n// Unio DS v2 — Button Component (2025 Enterprise Edition)\n// -----------------------------------------------------------------------------\n\nimport { forwardRef } from \"react\";\nimport type {\n  AnchorHTMLAttributes,\n  ButtonHTMLAttributes,\n  ElementType,\n} from \"react\";\nimport clsx from \"clsx\";\n\n// -----------------------------------------------------------------------------\n// Types\n// -----------------------------------------------------------------------------\ntype ButtonSize = \"sm\" | \"md\" | \"lg\";\ntype ButtonVariant =\n  | \"primary\"\n  | \"secondary\"\n  | \"outline-accent\"\n  | \"ghost\"\n  | \"icon\";\n\ntype BaseProps = {\n  children?: React.ReactNode;\n  variant?: ButtonVariant;\n  size?: ButtonSize;\n  className?: string;\n  disableFocusRing?: boolean;\n  fullWidth?: boolean; // ✅ Added to support block-level layouts\n};\n\ntype NativeProps = BaseProps &\n  ButtonHTMLAttributes<HTMLButtonElement> & { as?: \"button\" };\n\ntype AnchorProps = BaseProps &\n  AnchorHTMLAttributes<HTMLAnchorElement> & { as?: \"a\"; href: string };\n\ntype GenericLinkProps = BaseProps & { as?: React.ElementType; to?: string };\n\nexport type PolymorphicButtonProps =\n  | NativeProps\n  | AnchorProps\n  | GenericLinkProps;\n\n// -----------------------------------------------------------------------------\n// Component\n// -----------------------------------------------------------------------------\nexport const Button = forwardRef<\n  HTMLButtonElement | HTMLAnchorElement,\n  PolymorphicButtonProps\n>(function Button(\n  {\n    children,\n    variant = \"primary\",\n    size = \"md\",\n    className = \"\",\n    disableFocusRing = true,\n    fullWidth = false, // ✅ Defaulted to false\n    as = \"button\",\n    ...props\n  },\n  ref\n) {\n  // Base classes (applied to ALL buttons)\n  // Changed \"inline-flex\" to a dynamic check based on fullWidth\n  const base =\n    \"items-center justify-center rounded-md font-ui font-semibold leading-none \" +\n    \"transition-all duration-200 whitespace-nowrap select-none\";\n\n  // Sizes — match DS2 scale\n  const sizeClasses: Record<ButtonSize, string> = {\n    sm: \"h-9 px-4 text-small\",\n    md: \"h-11 px-5 text-base\",\n    lg: \"h-12 px-6 text-large\",\n  };\n\n  // For icon-only buttons\n  const iconSizeClasses: Record<ButtonSize, string> = {\n    sm: \"h-9 w-9 text-small\",\n    md: \"h-11 w-11 text-base\",\n    lg: \"h-12 w-12 text-large\",\n  };\n\n  // Variants — DS2 official\n  const variantStyles: Record<ButtonVariant, string> = {\n    primary: [\n      \"bg-accent text-background\",\n      \"hover:bg-accent-hover\",\n      \"active:translate-y-[1px] active:shadow-sm\",\n      \"shadow-sm hover:shadow-md\",\n      \"border border-transparent\",\n    ].join(\" \"),\n\n    secondary: [\n      \"border border-border-soft text-primary bg-transparent\",\n      \"hover:bg-foreground-muted/10\",\n      \"active:bg-foreground-muted/20\",\n    ].join(\" \"),\n\n    \"outline-accent\": [\n      \"border border-accent text-accent bg-transparent\",\n      \"hover:bg-accent/10\",\n      \"active:bg-accent/20\",\n    ].join(\" \"),\n\n    ghost: [\n      \"border border-transparent\",\n      \"text-foreground-muted\",\n      \"hover:bg-background-secondary/40\",\n      \"active:bg-background-secondary/60\",\n    ].join(\" \"),\n\n    icon: [\n      \"border border-transparent\",\n      \"text-foreground-muted\",\n      \"hover:bg-background-secondary/40\",\n      \"active:bg-background-secondary/60\",\n    ].join(\" \"),\n  };\n\n  // Focus ring handling\n  const focusStyles = disableFocusRing\n    ? \"focus:outline-none\"\n    : \"focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary/40 focus-visible:ring-offset-2 focus-visible:ring-offset-background\";\n\n  // Final classes\n  const classes = clsx(\n    base,\n    // Use flex vs inline-flex based on fullWidth\n    fullWidth ? \"flex w-full\" : \"inline-flex\",\n    variant === \"icon\" ? iconSizeClasses[size] : sizeClasses[size],\n    variantStyles[variant],\n    focusStyles,\n    className\n  );\n\n  const Component = as as ElementType;\n\n  return (\n    <Component className={classes} ref={ref} {...(props as any)}>\n      {children}\n    </Component>\n  );\n});\n\nButton.displayName = \"Button\";"]}
